// Check if K is enough to eat all piles within H hours
bool canEat(int piles[], int N, long long H, int K) {
    long long hours = 0;
    for (int i = 0; i < N; i++) {
        hours += (piles[i] + K - 1LL) / K; // ceil division
        if (hours > H) return false;
    }
    return true;
}

// Binary search to find minimum K
int findMinK(int piles[], int N, long long H) {
    int low = 1, high = 0;
    for (int i = 0; i < N; i++)
        high = max(high, piles[i]);

    int ans = high;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (canEat(piles, N, H, mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

