// Check if K is enough to eat all piles within H hours
function canEat(piles, H, K) {
    let hours = 0;
    for (let pile of piles) {
        hours += Math.ceil(pile / K);
        if (hours > H) return false;
    }
    return true;
}

// Binary search to find minimum K
function findMinK(piles, H) {
    let low = 1, high = Math.max(...piles);
    let ans = high;

    while (low <= high) {
        let mid = Math.floor(low + (high - low) / 2);
        if (canEat(piles, H, mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}
